# Check MEAI's AIFunction / AITool types
cat > Program.cs << 'EOF'
using System.Reflection;

var asm = Assembly.Load("Microsoft.Extensions.AI.Abstractions");
foreach (var t in asm.GetExportedTypes().Where(t => t.Name.Contains("AIFunction") || t.Name.Contains("AITool")).OrderBy(t => t.FullName))
{
    var kind = t.IsInterface ? "interface" : (t.IsAbstract ? "abstract class" : "class");
    Console.WriteLine($"\n{kind} {t.FullName}");
    // Static methods
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Static | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
        Console.WriteLine($"  static {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var c in t.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
        Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name} {{ {(p.CanRead?"get;":"")}{(p.CanWrite?" set;":"")} }}");
}
EOF
