using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------

var notebook = new Notebook();
var webSearcher = new WebSearcher();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearcher.SearchAsync, new AIFunctionFactoryOptions
    {
        Name = "search_web",
        Description = "Search the web for a query and return relevant snippets. "
                     + "Use this to find information about a research topic.",
    }),
    AIFunctionFactory.Create(notebook.SaveNote, new AIFunctionFactoryOptions
    {
        Name = "save_note",
        Description = "Save a research note with a title and body. "
                     + "Use this to record important findings during research.",
    }),
    AIFunctionFactory.Create(notebook.GetNotes, new AIFunctionFactoryOptions
    {
        Name = "get_notes",
        Description = "Retrieve all saved research notes. "
                     + "Use this to review what has been collected so far.",
    }),
};

// --- Agent setup -------------------------------------------------------------

IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

const string instructions = """
    You are a research agent. When given a topic:
    1. Search the web 2-3 times with different queries to gather broad information.
    2. Save key findings as notes using the save_note tool.
    3. Review your notes with get_notes.
    4. Produce a well-structured summary with sections, key facts, and source URLs.
    Be thorough but concise. Always cite sources.
    """;

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An agent that researches topics by searching the web and taking notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = tools,
        },
    });

// --- Run ---------------------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent           ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "";
}

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var session = await agent.CreateSessionAsync("research-1");
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
    Tools = tools,
});

var response = await agent.RunAsync(
    $"{instructions}\n\nResearch the following topic: {topic}",
    session,
    runOptions);

Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
Console.WriteLine(response.Text);
Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");

if (notebook.Count > 0)
{
    Console.WriteLine($"\n📝 {notebook.Count} note(s) saved during research.");
}

if (response.Usage is { } usage)
{
    Console.WriteLine($"📊 Tokens — input: {usage.InputTokenCount}, output: {usage.OutputTokenCount}, "
                    + $"total: {usage.TotalTokenCount}");
}

