// Tool implementations
// =============================================================================

/// <summary>Performs web searches by scraping DuckDuckGo HTML results.</summary>
sealed partial class WebSearcher
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    public async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url, cancellationToken);

            var results = ParseSearchResults(html);

            if (results.Count == 0)
                return $"No results found for: {query}";

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: {query}\n");
            foreach (var (title, snippet, link) in results.Take(5))
            {
                sb.AppendLine($"### {title}");
                sb.AppendLine(snippet);
                if (!string.IsNullOrEmpty(link))
                    sb.AppendLine($"Source: {link}");
                sb.AppendLine();
            }

            Console.WriteLine($"  ✅ Found {Math.Min(results.Count, 5)} results");
            return sb.ToString();
        }
        catch (Exception ex)
        {
            Console.WriteLine($"  ⚠️  Search failed: {ex.Message}");
            return $"Search failed for '{query}': {ex.Message}";
        }
    }

    private static List<(string Title, string Snippet, string Link)> ParseSearchResults(string html)
    {
        var results = new List<(string, string, string)>();

        var titlePattern = TitleRegex();
        var snippetPattern = SnippetRegex();
        var linkPattern = LinkRegex();

        var titles = titlePattern.Matches(html);
        var snippets = snippetPattern.Matches(html);
        var links = linkPattern.Matches(html);

        for (int i = 0; i < Math.Min(titles.Count, snippets.Count); i++)
        {
            var title = StripHtml(titles[i].Groups[1].Value);
            var snippet = StripHtml(snippets[i].Groups[1].Value);
            var link = i < links.Count ? WebUtility.HtmlDecode(links[i].Groups[1].Value) : "";

            // DuckDuckGo wraps links in a redirect; extract the real URL
            if (link.Contains("uddg="))
            {
                var match = UddgRegex().Match(link);
                if (match.Success)
                    link = WebUtility.UrlDecode(match.Groups[1].Value);
            }

            if (!string.IsNullOrWhiteSpace(title))
                results.Add((title.Trim(), snippet.Trim(), link));
        }

        return results;
    }

    private static string StripHtml(string html) =>
        WebUtility.HtmlDecode(HtmlTagRegex().Replace(html, ""));

    [GeneratedRegex("""<a[^>]*class="result__a"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex TitleRegex();

    [GeneratedRegex("""<a[^>]*class="result__snippet"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex("""<a[^>]*class="result__url"[^>]*href="([^"]*)"""")]
    private static partial Regex LinkRegex();

    [GeneratedRegex("""uddg=([^&]+)""")]
    private static partial Regex UddgRegex();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagRegex();
}

/// <summary>In-memory notebook for storing research notes.</summary>
sealed class Notebook
{
    private readonly List<Note> _notes = [];

    public int Count => _notes.Count;

    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("The content/body of the note")] string content)
    {
        _notes.Add(new Note(title, content, DateTime.UtcNow));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note '{title}' saved successfully. Total notes: {_notes.Count}";
    }

    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count}) ===\n");
        for (int i = 0; i < _notes.Count; i++)
        {
            var note = _notes[i];
            sb.AppendLine($"[{i + 1}] {note.Title}");
            sb.AppendLine($"    {note.Content}");
            sb.AppendLine();
        }

        return sb.ToString();
    }

    private sealed record Note(string Title, string Content, DateTime CreatedAt);
}

